const response = $input.first().json || {};
const countries = Array.isArray(response.countries) ? response.countries : [];

const map = {
  'United Kingdom': {
    url: 'https://www.gov.uk/student-visa',
    visa_type: 'UK Student Route Visa',
    processing_time: '3-8 weeks',
    visa_fee_inr: 52500,
    checklist: [
      { id: 'uk_1', category: 'Admission', item: 'CAS from UK university' },
      { id: 'uk_2', category: 'Financial', item: 'Proof of funds for tuition and living' }
    ]
  },
  'Canada': {
    url: 'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit.html',
    visa_type: 'Canada Study Permit',
    processing_time: '4-12 weeks',
    visa_fee_inr: 9200,
    checklist: [
      { id: 'ca_1', category: 'Admission', item: 'Letter of Acceptance (LOA)' },
      { id: 'ca_2', category: 'Financial', item: 'Proof of funds for tuition and living' }
    ]
  },
  'United States': {
    url: 'https://travel.state.gov/content/travel/en/us-visas/study/student-visa.html',
    visa_type: 'US F-1 Student Visa',
    processing_time: '2-8 weeks (varies by embassy)',
    visa_fee_inr: 15300,
    checklist: [
      { id: 'us_1', category: 'Admission', item: 'I-20 form from SEVP school' },
      { id: 'us_2', category: 'Fees', item: 'SEVIS fee payment confirmation' }
    ]
  },
  'Australia': {
    url: 'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/student-500',
    visa_type: 'Australia Student Visa (Subclass 500)',
    processing_time: '4-10 weeks',
    visa_fee_inr: 89000,
    checklist: [
      { id: 'au_1', category: 'Admission', item: 'Confirmation of Enrolment (CoE)' },
      { id: 'au_2', category: 'Health', item: 'Overseas Student Health Cover (OSHC)' }
    ]
  }
};

const picked = countries
  .filter((c) => map[c])
  .map((country) => ({
    json: {
      country,
      source_url: map[country].url,
      visa_type: map[country].visa_type,
      processing_time: map[country].processing_time,
      visa_fee_inr: map[country].visa_fee_inr,
      checklist: map[country].checklist
    }
  }));

if (!picked.length) {
  return Object.keys(map).map((country) => ({
    json: {
      country,
      source_url: map[country].url,
      visa_type: map[country].visa_type,
      processing_time: map[country].processing_time,
      visa_fee_inr: map[country].visa_fee_inr,
      checklist: map[country].checklist
    }
  }));
}

return picked;

const rows = $input.all();
const countries = {};
const documents = [];

for (const row of rows) {
  const j = row.json || {};
  const country = j.country;
  if (!country) continue;

  countries[country] = {
    visa_type: j.visa_type || 'Student Visa',
    official_link: j.source_url || '',
    processing_time: j.processing_time || '',
    visa_fee_inr: Number(j.visa_fee_inr || 0),
    checklist: Array.isArray(j.checklist) ? j.checklist : []
  };

  const raw = (j.body || j.data || '').toString();
  const text = raw
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 3500);

  documents.push({
    country,
    filename: country.toLowerCase().replace(/[^a-z0-9]+/g, '_') + '_student_visa.md',
    official_link: j.source_url || '',
    content: text || `Official guidance not parsed. Visit ${j.source_url || 'official source'} for latest details.`
  });
}

return [{ json: { countries, documents } }];
